import { colors } from "./model.mjs";

const HEADER = `/**
 * Houston design tokens — semantic colour custom properties.
 * AUTO-GENERATED by @houston/design-tokens. Do NOT edit by hand.
 * Source: tokens/*.json  ·  Rebuild: pnpm --filter @houston/design-tokens build
 *
 * These are the same --ht-* variable names the app and @houston-ai/* packages
 * already consume; @theme (in @houston-ai/core) re-exports them to Tailwind's
 * --color-* utilities. Light lives on :root, dark on [data-theme="dark"] —
 * mirroring how app/src/lib/theme.ts toggles the theme.
 */`;

function block(selector, entries) {
  const lines = entries.map(({ name, value }) => `  --ht-${name}: ${value};`);
  return `${selector} {\n${lines.join("\n")}\n}`;
}

/**
 * @param {import("./collect.mjs").collect} _
 * @param {{ path: string[], value: string }[]} light
 * @param {{ path: string[], value: string }[]} dark
 */
export function buildCss(light, dark) {
  return [
    HEADER,
    "",
    block(":root", colors(light)),
    "",
    block('[data-theme="dark"]', colors(dark)),
    "",
  ].join("\n");
}
